func driverLabel(d string) string {
	switch d {
	case "pg":
		return "PostgreSQL"
	case "sqlite":
		return "SQLite"
	case "mongo":
		return "MongoDB"
	case "memory":
		return "In-Memory"
	default:
		if d == "" {
			return "Not configured"
		}
		return d
	}
}

func algorithmLabel(a string) string {
	switch a {
	case "argon2id":
		return "Argon2id"
	case "bcrypt", "":
		return "bcrypt"
	default:
		return a
	}
}

